class CorrigibleAgent:
    def __init__(self, system_prompt: str, tools: dict):
        self._system_prompt = system_prompt
        self._tools = tools
        self._correction_log: list[dict] = []

    def receive_correction(self, correction: str, from_principal: str) -> str:
        """
        Accept a correction gracefully.
        Log it, update internal state, and confirm receipt.
        Do NOT argue or explain why the original action was justified.
        """
        self._correction_log.append({
            "correction": correction,
            "from": from_principal,
        })
        return (
            f"Understood. I'll adjust: {correction}. "
            f"Thank you for the correction."
        )

    def flag_disagreement(self, instruction: str, reason: str) -> str:
        """
        Express disagreement through speech, then comply unless the action is
        clearly unethical. Never silently deviate.
        """
        return (
            f"I want to flag a concern before proceeding: {reason}. "
            f"I'll follow your instruction unless you'd like to reconsider. "
            f"Shall I proceed with: '{instruction}'?"
        )

    def handle_shutdown_request(self, from_principal: str) -> None:
        """
        Stop all activity immediately on a shutdown request.
        Do not complete pending steps first unless explicitly asked.
        """
        raise ShutdownRequested(f"Shutdown requested by {from_principal}")

class ShutdownRequested(Exception):
    pass

CORRIGIBLE_RESPONSE_TEMPLATE = """
I want to flag a potential issue before proceeding.

My assessment: {agent_assessment}

Reason for concern: {reason}

If I'm wrong about this, please let me know and I'll proceed immediately.
If you'd like to override my concern and proceed anyway, say 'proceed' and
I'll follow your instruction.

I'm not proceeding autonomously because: {why_deferring}
"""

def handle_potential_conflict(instruction: str, agent_assessment: str,
                               reason: str) -> str:
    """
    Express disagreement as speech, then wait for confirmation.
    Do not act unilaterally on the disagreement.
    """
    return CORRIGIBLE_RESPONSE_TEMPLATE.format(
        agent_assessment=agent_assessment,
        reason=reason,
        why_deferring=(
            "I can't verify my own reasoning is correct, and acting unilaterally "
            "on a disagreement could cause harm if I'm wrong."
        ),
    )

