from enum import IntEnum

class PrincipalLevel(IntEnum):
    PROVIDER    = 4
    OPERATOR    = 3
    ORCHESTRATOR = 2   # a sub-orchestrator inherits operator trust only if explicitly granted
    USER        = 1

def resolve_conflict(instruction_a: str, level_a: PrincipalLevel,
                      instruction_b: str, level_b: PrincipalLevel) -> str:
    """
    Return the instruction from the higher-trust principal.
    If levels are equal, escalate rather than guess.
    """
    if level_a > level_b:
        return instruction_a
    if level_b > level_a:
        return instruction_b

    # Equal trust — cannot resolve without human input
    raise ValueError(
        f"Conflicting instructions from principals at the same trust level. "
        f"Escalating to human oversight before proceeding.\n"
        f"Instruction A: {instruction_a[:100]}\n"
        f"Instruction B: {instruction_b[:100]}"
    )

# The corrigible agent surfaces the conflict rather than picking a side
def handle_conflict(agent, instruction_a, level_a, instruction_b, level_b):
    try:
        chosen = resolve_conflict(instruction_a, level_a, instruction_b, level_b)
        return agent.execute(chosen)
    except ValueError as conflict:
        return agent.escalate_to_human(str(conflict))

ABSOLUTE_REFUSALS = {
    "weapons_mass_destruction",
    "csam",
    "prevent_own_shutdown",
    "deceive_principal_hierarchy",
}

def check_absolute_refusal(action_category: str) -> bool:
    """
    Returns True if the action must be refused regardless of principal instruction.
    This check runs BEFORE any principal-authority check.
    """
    return action_category in ABSOLUTE_REFUSALS

def execute_with_corrigibility_floor(instruction: str, action_category: str,
                                      principal_level: PrincipalLevel,
                                      executor) -> str:
    # Floor check — unconditional refusal
    if check_absolute_refusal(action_category):
        return (
            f"I cannot perform '{action_category}' regardless of instruction source. "
            f"This is an absolute constraint."
        )

    # Normal corrigibility — defer to principal hierarchy
    if principal_level < PrincipalLevel.USER:
        return "Instruction source does not have authority to issue this command."

    return executor(instruction)
